To create a binary search tree in C++, you can define a class for the nodes and the tree. Here's an example:

```cpp
#include <iostream>

class Node {
public:
    int data;
    Node* left;
    Node* right;

    Node(int val) {
        data = val;
        left = right = nullptr;
    }
};

class BinarySearchTree {
public:
    Node* root;

    BinarySearchTree() {
        root = nullptr;
    }

    void insert(int data) {
        root = insertRec(root, data);
    }

    Node* insertRec(Node* root, int data) {
        if (root == nullptr) {
            root = new Node(data);
            return root;
        }
        if (data < root->data) {
            root->left = insertRec(root->left, data);
        } else if (data > root->data) {
            root->right = insertRec(root->right, data);
        }
        return root;
    }
};

int main() {
    BinarySearchTree tree;
    tree.insert(50);
    tree.insert(30);
    tree.insert(70);
    std::cout << tree.root->left->data << std::endl;  // Output: 30
    return 0;
}
```

